import sys

def main():
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Find the boundaries of the original rectangle
    top = None
    bottom = None
    left = None
    right = None

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                if top is None:
                    top = i
                bottom = i
                if left is None or j < left:
                    left = j
                if right is None or j > right:
                    right = j

    # The original rectangle is from (top, left) to (bottom, right)
    # Now find the missing cell in this rectangle
    for i in range(top, bottom + 1):
        for j in range(left, right + 1):
            if grid[i][j] == '.':
                print(i + 1, j + 1)
                return

if __name__ == "__main__":
    main()
